}

package com.bloommood.service;

import com.bloommood.entity.Action;
import com.bloommood.entity.ActionType;
import com.bloommood.entity.User;
import com.bloommood.repository.ActionRepository;
import com.bloommood.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.*;
import java.util.List;

@Service
public class ActionService {

    private final ActionRepository actionRepository;
    private final UserRepository userRepository;

    public ActionService(ActionRepository actionRepository, UserRepository userRepository) {
        this.actionRepository = actionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public Action createAction(Long uid, ActionType type) {
        if (type == null) {
            throw new IllegalArgumentException("type required");
        }

        User user = userRepository.findById(uid).orElse(null);
        if (user == null) {
            throw new IllegalArgumentException("user not found");
        }

        Action a = new Action(user, type, LocalDateTime.now());
        return actionRepository.save(a);
    }

    @Transactional(readOnly = true)
    public List<Action> getActionsForMonth(Long uid, YearMonth ym) {
        ZoneId zone = ZoneId.systemDefault();
        LocalDateTime start = ym.atDay(1).atStartOfDay();
        // endExclusive: first moment of next month
        LocalDateTime end = ym.plusMonths(1).atDay(1).atStartOfDay();
        return actionRepository.findAllByUser_UidAndActionTimeBetweenOrderByActionTimeAsc(uid, start, end);
    }


}

package com.bloommood.service;

import com.bloommood.entity.Action;
import com.bloommood.entity.ActionType;
import com.bloommood.entity.Plant;
import com.bloommood.entity.PlantStatus;
import com.bloommood.entity.User;
import com.bloommood.repository.ActionRepository;
import com.bloommood.repository.PlantRepository;
import com.bloommood.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.*;
import java.time.temporal.ChronoUnit;
import java.util.List;

@Service
public class ActionService {

    private final ActionRepository actionRepository;
    private final UserRepository userRepository;
    private final PlantRepository plantRepository;

    public ActionService(ActionRepository actionRepository, UserRepository userRepository, PlantRepository plantRepository) {
        this.actionRepository = actionRepository;
        this.userRepository = userRepository;
        this.plantRepository = plantRepository;
    }

    @Transactional
    public Action createAction(Long uid, ActionType type) {
        if (type == null) {
            throw new IllegalArgumentException("type required");
        }

        User user = userRepository.findById(uid).orElse(null);
        if (user == null) {
            throw new IllegalArgumentException("user not found");
        }

        Plant plant = plantRepository.findTopByUser_UidOrderByPlantDateDescPidDesc(uid).orElse(null);
        if (plant == null) {
            throw new IllegalArgumentException("no plant to interact with");
        }

        LocalDate today = LocalDate.now();
        applyWitherIfIdle(plant, today);

        int stage = plant.getStage() == null ? 1 : plant.getStage();
        if (stage < 4 && canGrowOnDate(plant.getLastInteraction(), today)) {
            plant.setStage(stage + 1);
        }

        plant.setLastInteraction(today);
        if (type == ActionType.WATER && plant.getStatus() != PlantStatus.DEAD) {
            plant.setStatus(PlantStatus.NORMAL);
        }
        plantRepository.save(plant);

        Action a = new Action(user, type, LocalDateTime.now());
        return actionRepository.save(a);
    }

    @Transactional(readOnly = true)
    public List<Action> getActionsForMonth(Long uid, YearMonth ym) {
        LocalDateTime start = ym.atDay(1).atStartOfDay();
        // endExclusive: first moment of next month
        LocalDateTime end = ym.plusMonths(1).atDay(1).atStartOfDay();
        return actionRepository.findAllByUser_UidAndActionTimeBetweenOrderByActionTimeAsc(uid, start, end);
    }

    private void applyWitherIfIdle(Plant plant, LocalDate today) {
        if (plant.getStatus() == PlantStatus.DEAD) {
            return;
        }
        LocalDate lastInteraction = plant.getLastInteraction() == null ? plant.getPlantDate() : plant.getLastInteraction();
        long idleDays = ChronoUnit.DAYS.between(lastInteraction, today);
        if (plant.getStatus() == PlantStatus.NORMAL && idleDays >= 7) {
            plant.setStatus(PlantStatus.WITHERED);
        }
    }

    private boolean canGrowOnDate(LocalDate lastInteraction, LocalDate today) {
        // One stage growth per calendar day.
        return lastInteraction == null || lastInteraction.isBefore(today);
    }

}

package com.bloommood.service;

import com.bloommood.dto.MonthPlantDayDto;
import com.bloommood.dto.PlantUpdateRequest;
import com.bloommood.dto.PlantViewDto;
import com.bloommood.entity.Plant;
import com.bloommood.entity.PlantType;
import com.bloommood.entity.User;
import com.bloommood.repository.PlantRepository;
import com.bloommood.repository.UserRepository;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDate;
import java.time.YearMonth;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Service
public class PlantService {

    private final PlantRepository plantRepository;
    private final UserRepository userRepository;

    public PlantService(PlantRepository plantRepository, UserRepository userRepository) {
        this.plantRepository = plantRepository;
        this.userRepository = userRepository;
    }

    @Transactional(readOnly = true)
    public Plant getTodayPlant(Long uid) {
        LocalDate today = LocalDate.now();
        return plantRepository.findByUser_UidAndPlantDate(uid, today).orElse(null);
    }

    @Transactional
    public Plant CreateTodayPlant(Long uid, PlantType requestedType) {
        LocalDate today = LocalDate.now();

        Plant existing = plantRepository.findByUser_UidAndPlantDate(uid, today).orElse(null);
        if (existing != null) {
            throw new IllegalArgumentException("plant already exists for today");
        }
        User user = userRepository.findById(uid).orElse(null);
        if (user == null) {
            throw new IllegalArgumentException("user not found");
        }

        PlantType type = (requestedType == null) ? PlantType.FLOWER : requestedType;
        Plant plant = new Plant(user, today, type);

        try {
            return plantRepository.save(plant);
        } catch (DataIntegrityViolationException e) {
            // Concurrent request: (uid, plant_date) unique constraint hit.
            return plantRepository.findByUser_UidAndPlantDate(uid, today)
                    .orElseThrow(() -> e);
        }
    }

    @Transactional(readOnly = true)
    public List<Plant> getPlantsForMonth(Long uid, YearMonth month) {
        LocalDate start = month.atDay(1);
        LocalDate end = month.atEndOfMonth();
        return plantRepository.findAllByUser_UidAndPlantDateBetweenOrderByPlantDateAsc(uid, start, end);
    }

    @Transactional(readOnly = true)
    public List<MonthPlantDayDto> getMonthCalendar(Long uid, YearMonth month) {
        List<Plant> planted = getPlantsForMonth(uid, month);

        Map<LocalDate, Plant> byDate = planted.stream()
                .collect(Collectors.toMap(Plant::getPlantDate, p -> p));

        int days = month.lengthOfMonth();
        java.util.ArrayList<MonthPlantDayDto> out = new java.util.ArrayList<>(days);

        for (int d = 1; d <= days; d++) {
            LocalDate date = month.atDay(d);
            Plant p = byDate.get(date);
            if (p == null) {
                out.add(MonthPlantDayDto.empty(date));
            } else {
                PlantViewDto dto = new PlantViewDto(p.getPid(), p.getPlantDate(), p.getType(), p.getStatus(), p.getStage());
                out.add(MonthPlantDayDto.of(date, dto));
            }
        }

        return out;
    }

    @Transactional
    public Plant updatePlant(Long uid, Long pid, PlantUpdateRequest req) {
        Plant plant = plantRepository.findByPidAndUser_Uid(pid, uid).orElse(null);
        if (plant == null) {
            throw new IllegalArgumentException("plant not found");
        }

        boolean changed = false;

        if (req.getType() != null) {
            plant.setType(req.getType());
            changed = true;
        }
        if (req.getStatus() != null) {
            plant.setStatus(req.getStatus());
            changed = true;
        }
        if (req.getStage() != null) {
            if (req.getStage() < 0) {
                throw new IllegalArgumentException("stage must be >= 0");
            }
            plant.setStage(req.getStage());
            changed = true;
        }

        if (!changed) {
            return plant;
        }

        return plantRepository.save(plant);
    }

    @Transactional
    public void deletePlant(Long uid, Long pid) {
        Plant plant = plantRepository.findByPidAndUser_Uid(pid, uid).orElse(null);
        if (plant == null) {
            throw new IllegalArgumentException("plant not found");
        }
        plantRepository.delete(plant);
    }
}

package com.bloommood.service;

import com.bloommood.dto.MonthPlantDayDto;
import com.bloommood.dto.PlantUpdateRequest;
import com.bloommood.dto.PlantViewDto;
import com.bloommood.entity.Plant;
import com.bloommood.entity.PlantStatus;
import com.bloommood.entity.PlantType;
import com.bloommood.entity.User;
import com.bloommood.repository.PlantRepository;
import com.bloommood.repository.UserRepository;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDate;
import java.time.YearMonth;
import java.time.temporal.ChronoUnit;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Service
public class PlantService {

    private final PlantRepository plantRepository;
    private final UserRepository userRepository;

    public PlantService(PlantRepository plantRepository, UserRepository userRepository) {
        this.plantRepository = plantRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public Plant getTodayPlant(Long uid) {
        LocalDate today = LocalDate.now();
        Plant plant = plantRepository.findByUser_UidAndPlantDate(uid, today).orElse(null);
        if (plant == null) {
            return null;
        }
        refreshWitherStatus(plant, today);
        return plant;
    }

    @Transactional
    public Plant CreateTodayPlant(Long uid, PlantType requestedType) {
        LocalDate today = LocalDate.now();

        Plant existing = plantRepository.findByUser_UidAndPlantDate(uid, today).orElse(null);
        if (existing != null) {
            throw new IllegalArgumentException("plant already exists for today");
        }
        User user = userRepository.findById(uid).orElse(null);
        if (user == null) {
            throw new IllegalArgumentException("user not found");
        }

        PlantType type = (requestedType == null) ? PlantType.FLOWER : requestedType;
        Plant plant = new Plant(user, today, type);

        try {
            return plantRepository.save(plant);
        } catch (DataIntegrityViolationException e) {
            // Concurrent request: (uid, plant_date) unique constraint hit.
            return plantRepository.findByUser_UidAndPlantDate(uid, today)
                    .orElseThrow(() -> e);
        }
    }

    @Transactional(readOnly = true)
    public List<Plant> getPlantsForMonth(Long uid, YearMonth month) {
        LocalDate start = month.atDay(1);
        LocalDate end = month.atEndOfMonth();
        return plantRepository.findAllByUser_UidAndPlantDateBetweenOrderByPlantDateAsc(uid, start, end);
    }

    @Transactional
    public List<MonthPlantDayDto> getMonthCalendar(Long uid, YearMonth month) {
        List<Plant> planted = getPlantsForMonth(uid, month);
        LocalDate today = LocalDate.now();

        planted.forEach(p -> refreshWitherStatus(p, today));

        Map<LocalDate, Plant> byDate = planted.stream()
                .collect(Collectors.toMap(Plant::getPlantDate, p -> p));

        int days = month.lengthOfMonth();
        java.util.ArrayList<MonthPlantDayDto> out = new java.util.ArrayList<>(days);

        for (int d = 1; d <= days; d++) {
            LocalDate date = month.atDay(d);
            Plant p = byDate.get(date);
            if (p == null) {
                out.add(MonthPlantDayDto.empty(date));
            } else {
                PlantViewDto dto = toViewDto(p);
                out.add(MonthPlantDayDto.of(date, dto));
            }
        }

        return out;
    }

    @Transactional
    public Plant updatePlant(Long uid, Long pid, PlantUpdateRequest req) {
        Plant plant = plantRepository.findByPidAndUser_Uid(pid, uid).orElse(null);
        if (plant == null) {
            throw new IllegalArgumentException("plant not found");
        }

        boolean changed = false;

        if (req.getType() != null) {
            plant.setType(req.getType());
            changed = true;
        }
        if (req.getStatus() != null) {
            plant.setStatus(req.getStatus());
            changed = true;
        }
        if (req.getStage() != null) {
            if (req.getStage() < 0) {
                throw new IllegalArgumentException("stage must be >= 0");
            }
            plant.setStage(req.getStage());
            changed = true;
        }

        if (!changed) {
            return plant;
        }

        return plantRepository.save(plant);
    }

    @Transactional
    public void deletePlant(Long uid, Long pid) {
        Plant plant = plantRepository.findByPidAndUser_Uid(pid, uid).orElse(null);
        if (plant == null) {
            throw new IllegalArgumentException("plant not found");
        }
        plantRepository.delete(plant);
    }

    public PlantViewDto toViewDto(Plant p) {
        return new PlantViewDto(
                p.getPid(),
                p.getPlantDate(),
                p.getType(),
                p.getStatus(),
                p.getStage(),
                p.getLastInteraction()
        );
    }

    private void refreshWitherStatus(Plant plant, LocalDate today) {
        if (plant.getStatus() == PlantStatus.DEAD) {
            return;
        }
        LocalDate lastInteraction = plant.getLastInteraction();
        if (lastInteraction == null) {
            lastInteraction = plant.getPlantDate();
            plant.setLastInteraction(lastInteraction);
        }

        long idleDays = ChronoUnit.DAYS.between(lastInteraction, today);
        if (plant.getStatus() == PlantStatus.NORMAL && idleDays >= 7) {
            plant.setStatus(PlantStatus.WITHERED);
        }
    }
}

package com.bloommood.service;

import com.bloommood.entity.Action;
import com.bloommood.entity.ActionType;
import com.bloommood.entity.User;
import com.bloommood.repository.ActionRepository;
import com.bloommood.repository.UserRepository;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.transaction.annotation.Transactional;

import java.time.YearMonth;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@Transactional
class ActionServiceTests {

    @Autowired
    ActionService actionService;

    @Autowired
    UserRepository userRepository;

    @Autowired
    ActionRepository actionRepository;

    @Test
    void createAction_persists() {
        User u = userRepository.save(new User("asvc@test.com", "A", "hash", "ROLE_USER"));
        Action a = actionService.createAction(u.getUid(), ActionType.WATER);
        assertNotNull(a.getId());
        assertEquals(ActionType.WATER, a.getType());
    }

    @Test
    void getActionsForMonth_returnsList() {
        User u = userRepository.save(new User("asvc2@test.com", "A2", "hash", "ROLE_USER"));
        actionService.createAction(u.getUid(), ActionType.SUN);

        var list = actionService.getActionsForMonth(u.getUid(), YearMonth.now());
        assertFalse(list.isEmpty());
    }
}

package com.bloommood.service;

import com.bloommood.entity.Action;
import com.bloommood.entity.ActionType;
import com.bloommood.entity.Plant;
import com.bloommood.entity.PlantStatus;
import com.bloommood.entity.PlantType;
import com.bloommood.entity.User;
import com.bloommood.repository.ActionRepository;
import com.bloommood.repository.PlantRepository;
import com.bloommood.repository.UserRepository;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.transaction.annotation.Transactional;

import java.time.YearMonth;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@Transactional
class ActionServiceTests {

    @Autowired
    ActionService actionService;

    @Autowired
    UserRepository userRepository;

    @Autowired
    ActionRepository actionRepository;

    @Autowired
    PlantRepository plantRepository;

    @Test
    void createAction_persists() {
        User u = userRepository.save(new User("asvc@test.com", "A", "hash", "ROLE_USER"));
        plantRepository.save(new Plant(u, java.time.LocalDate.now(), PlantType.FLOWER));
        Action a = actionService.createAction(u.getUid(), ActionType.WATER);
        assertNotNull(a.getId());
        assertEquals(ActionType.WATER, a.getType());
    }

    @Test
    void getActionsForMonth_returnsList() {
        User u = userRepository.save(new User("asvc2@test.com", "A2", "hash", "ROLE_USER"));
        plantRepository.save(new Plant(u, java.time.LocalDate.now(), PlantType.TREE));
        actionService.createAction(u.getUid(), ActionType.SUN);

        var list = actionService.getActionsForMonth(u.getUid(), YearMonth.now());
        assertFalse(list.isEmpty());
    }

    @Test
    void createAction_sameDayOnlyGrowsOnceWithoutError() {
        User u = userRepository.save(new User("asvc3@test.com", "A3", "hash", "ROLE_USER"));
        Plant p = plantRepository.save(new Plant(u, java.time.LocalDate.now(), PlantType.CACTUS));

        actionService.createAction(u.getUid(), ActionType.SUN);
        actionService.createAction(u.getUid(), ActionType.FERTILIZE);
        actionService.createAction(u.getUid(), ActionType.WATER);
        actionService.createAction(u.getUid(), ActionType.SUN);

        Plant updated = plantRepository.findById(p.getPid()).orElseThrow();
        assertEquals(2, updated.getStage());
    }

    @Test
    void createAction_waterRecoversWitheredWithoutStageDrop() {
        User u = userRepository.save(new User("asvc4@test.com", "A4", "hash", "ROLE_USER"));
        Plant p = new Plant(u, java.time.LocalDate.now().minusDays(10), PlantType.FLOWER);
        p.setStage(4);
        p.setStatus(PlantStatus.WITHERED);
        p.setLastInteraction(java.time.LocalDate.now().minusDays(10));
        p = plantRepository.save(p);

        actionService.createAction(u.getUid(), ActionType.WATER);

        Plant updated = plantRepository.findById(p.getPid()).orElseThrow();
        assertEquals(PlantStatus.NORMAL, updated.getStatus());
        assertEquals(4, updated.getStage());
    }
}
